import math
from functools import lru_cache

@lru_cache(maxsize=None)
def bernoulli_number(n):
    if n == 0:
        return 1
    elif n == 1:
        return 1/2
    elif n % 2 != 0:
        return 0
    else:
        B = [0] * (n + 1)
        for m in range(n + 1):
            B[m] = 0
            for j in range(m + 1):
                B[m] += math.comb(m + 1, j) * B[j] / (m + 2 - j)
        return B[n]

def faulhaber_sum(n, k):
    if k == 0:
        return n
    total = 0
    for i in range(k + 1):
        term = math.comb(k + 1, i) * bernoulli_number(i) * (n + 1) ** (k + 1 - i)
        total += term
    return total // (k + 1)

# Example usage:
n = 10
k = 3
print(faulhaber_sum(n, k))  # Output: 3025 (sum of cubes from 1 to 10)
